"use client";

import * as React from "react";
import {
  ArrowLeftToLine,
  Command,
} from "lucide-react";

import { NavMain } from "./nav-main";
import { NavProjects } from "./nav-projects";
import {
  Sidebar,
  SidebarContent,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  useSidebar,
} from "@/components/ui/sidebar";
import { SearchForm } from "./search-form";
import { NavSupport } from "./nav-support";
import { NavApps } from "./nav-apps";
import { NavManagement } from "./nav-management";
import { data } from "../data";

export function AppSidebar({ ...props }: React.ComponentProps<typeof Sidebar>) {
  const { toggleSidebar } = useSidebar();
  return (
    <Sidebar variant="inset" {...props}>
      <SidebarHeader>
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton
              size="lg"
              className="bg-background border border-border transition-colors hover:bg-muted group/profile outline-none focus-visible:ring-0"
            >
              <div className="bg-sidebar-primary text-sidebar-primary-foreground flex aspect-square size-8 items-center justify-center rounded-md">
                <Command className="size-4" />
              </div>
              <div className="grid flex-1 text-left text-sm leading-tight">
                <span className="truncate">Courtney Henry</span>
                <span className="truncate text-[10px] mt-0.5 text-neutral-500">
                  The Walt Disney Company
                </span>
              </div>
              <ArrowLeftToLine
                onClick={() => {
                  toggleSidebar();
                }}
                className="size-4 text-muted-foreground transition-colors cursor-pointer hover:text-primary outline-none focus-visible:ring-0"
              />
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarHeader>
      <SidebarContent className="py-3 gap-0">
        <SearchForm />
        <NavMain items={data.navMain} />
        <NavProjects projects={data.projects} />
        <NavManagement management={data.management} />
        <NavSupport support={data.support} />
        <NavApps apps={data.apps} />
      </SidebarContent>
    </Sidebar>
  );
}

"use client"

import { type LucideIcon } from "lucide-react"

import {
  SidebarGroup,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@/components/ui/sidebar"

export function NavMain({
  items,
}: {
  items: {
    title: string
    url: string
    icon: LucideIcon
    isActive?: boolean
    isDisabled?: boolean
  }[]
}) {
  return (
    <SidebarGroup>
      <SidebarGroupLabel className="-ml-2 font-medium text-neutral-700 dark:text-neutral-300">Essentials</SidebarGroupLabel>
      <SidebarMenu>
        {items.map((item) => (
          <SidebarMenuItem key={item.title} className="group/nav-item">
            <SidebarMenuButton asChild tooltip={item.title} className="text-neutral-500 dark:text-neutral-400 text-xs h-8 font-medium hover:bg-neutral-100 dark:hover:bg-neutral-800/50 data-[active=true]:bg-neutral-100 dark:data-[active=true]:bg-neutral-800/50 data-[active=true]:text-neutral-600 dark:data-[active=true]:text-neutral-300 hover:text-neutral-600 dark:hover:text-neutral-300 transition-colors outline-none focus-visible:ring-0">
              <a href={item.isDisabled ? "#" : item.url} onClick={(e) => {
                if (item.isDisabled) {
                  e.preventDefault();
                }
              }}>
                <item.icon className="size-4! transition-colors group-hover/nav-item:text-neutral-800 dark:group-hover/nav-item:text-neutral-200" />
                <span className="tracking-tight">{item.title}</span>
              </a>
            </SidebarMenuButton>
          </SidebarMenuItem>
        ))}
      </SidebarMenu>
    </SidebarGroup>
  )
}

import { AppSidebar } from "./components/app-sidebar";
import { SidebarInset, SidebarProvider, SidebarTrigger, useSidebar } from "@/components/ui/sidebar";

const DashboardHeader = () => {
  const { open, isMobile, openMobile } = useSidebar();
  const isOpen = isMobile ? openMobile : open;

  return (
    <header className="flex h-9 p-3 shrink-0 items-center gap-2 ">
      {!isOpen && <SidebarTrigger className="-ml-1" />}
      <h3 className="text-sm text-neutral-600">Settings</h3>
    </header>
  );
};

export const DashboardLayout = ({
  children,
}: {
  children: React.ReactNode;
}) => {
  return (
    <SidebarProvider className="bg-sidebar">
      <AppSidebar />
      <SidebarInset className="rounded-md! shadow-none! border border-border">
        <DashboardHeader />
        <main className="flex-1 overflow-auto">{children}</main>
      </SidebarInset>
    </SidebarProvider>
  );
};

